    })
  } else {
    console.log('  ℹ️  최근 판매 데이터가 없습니다.')
  }

  // 4. 세트 구성품 정보 확인
  if (setBarcodes && setBarcodes.length > 0) {
    console.log('\n🔧 세트 구성품:')
    for (const set of setBarcodes) {
      const { data: compositions, error: compError } = await supabase
        .from('set_composition')
        .select('*')
        .eq('set_barcode', set.set_barcode)

      console.log(`\n  ${set.set_barcode}:`)
      if (compError) {
        console.error('    ❌ 조회 실패:', compError)
      } else if (compositions && compositions.length > 0) {
        compositions.forEach(c => {
          console.log(`    - ${c.component_barcode} x ${c.quantity}`)
        })
      } else {
        console.log('    ⚠️  구성품이 등록되지 않았습니다!')
      }
    }
  }
}

checkTigardenSet()

