  if (setBarcodeError) {
    result.setBarcodeError = setBarcodeError.message
  } else {
    result.setBarcodes = setBarcodes || []
  }

  // 2. product_barcodes에서 티가든 제품 조회
  const { data: productBarcodes, error: productError } = await supabase
    .from('product_barcodes')
    .select('barcode, product_name')
    .or('product_name.ilike.%티가든%,product_name.ilike.%happier%,product_name.ilike.%블랭킷%')

  if (productError) {
    result.productError = productError.message
  } else {
    result.productBarcodes = productBarcodes || []
  }

  // 3. daily_sales에서 티가든 세트 판매 데이터 확인
  const { data: salesData, error: salesError } = await supabase
    .from('daily_sales')
    .select(`
      *,
      product_barcodes (
        product_name
      )
    `)
    .or('product_barcode.ilike.%티가든%,product_barcode.ilike.%happier%,product_barcode.ilike.%블랭킷%')
    .order('sale_date', { ascending: false })
    .limit(10)

  if (salesError) {
    result.salesError = salesError.message
  } else {
    result.salesData = salesData || []
  }

  // 4. 세트 구성품 정보 확인
  if (setBarcodes && setBarcodes.length > 0) {
    for (const set of setBarcodes) {
      const { data: compositions, error: compError } = await supabase
        .from('set_composition')
        .select('*')
        .eq('set_barcode', set.set_barcode)

      if (compError) {
        result.compositions.push({
          setBarcode: set.set_barcode,
          error: compError.message
        })
      } else {
        result.compositions.push({
          setBarcode: set.set_barcode,
          items: compositions || []
        })
      }
    }
  }

  return NextResponse.json(result)
}

