    ]
  },
  {
    setBarcode: 'LEC101S00100C',
    setName: '티가든블랭킷_Milder_세트C',
    components: [
      { barcode: 'LEC1012001002', quantity: 2 }  // 미디움
    ]
  },
  // Fresher 세트
  {
    setBarcode: 'LEC101S00200A',
    setName: '티가든블랭킷_Fresher_세트A',
    components: [
      { barcode: 'LEC1012002001', quantity: 2 }, // 라지
      { barcode: 'LEC1012002002', quantity: 1 }  // 미디움
    ]
  },
  {
    setBarcode: 'LEC101S00200B',
    setName: '티가든블랭킷_Fresher_세트B',
    components: [
      { barcode: 'LEC1012002001', quantity: 1 }, // 라지
      { barcode: 'LEC1012002002', quantity: 1 }  // 미디움
    ]
  },
  {
    setBarcode: 'LEC101S00200C',
    setName: '티가든블랭킷_Fresher_세트C',
    components: [
      { barcode: 'LEC1012002002', quantity: 2 }  // 미디움
    ]
  },
  // Happier 세트
  {
    setBarcode: 'LEC101S00300A',
    setName: '티가든블랭킷_Happier_세트A',
    components: [
      { barcode: 'LEC1012003001', quantity: 2 }, // 라지
      { barcode: 'LEC1012003002', quantity: 1 }  // 미디움
    ]
  },
  {
    setBarcode: 'LEC101S00300B',
    setName: '티가든블랭킷_Happier_세트B',
