      { barcode: 'LEC1012003002', quantity: 1 }  // 미디움
    ]
  },
  {
    setBarcode: 'LEC101S00300C',
    setName: '티가든블랭킷_Happier_세트C',
    components: [
      { barcode: 'LEC1012003002', quantity: 2 }  // 미디움
    ]
  }
]

async function fixTigardenSets() {
  console.log('🔧 티가든블랭킷 세트 수정 시작...\n')

  const setBarcodes = setCompositions.map(s => s.setBarcode)

  // 1. product_barcodes에서 삭제
  console.log('1️⃣ product_barcodes에서 세트 바코드 삭제 중...')
  const { error: deleteError } = await supabase
    .from('product_barcodes')
    .delete()
    .in('barcode', setBarcodes)

  if (deleteError) {
    console.error('❌ 삭제 실패:', deleteError)
    return
  }
  console.log(`✅ ${setBarcodes.length}개 세트 바코드 삭제 완료\n`)

  // 2. set_barcodes에 추가
  console.log('2️⃣ set_barcodes에 세트 등록 중...')
  const setBarcodesData = setCompositions.map(s => ({
    set_barcode: s.setBarcode,
    set_name: s.setName,
    created_at: new Date().toISOString(),
    updated_at: new Date().toISOString()
  }))

  const { error: insertSetError } = await supabase
    .from('set_barcodes')
    .insert(setBarcodesData)

  if (insertSetError) {
    console.error('❌ 세트 등록 실패:', insertSetError)
    return
  }
  console.log(`✅ ${setBarcodesData.length}개 세트 등록 완료\n`)

  // 3. set_composition에 구성품 추가
  console.log('3️⃣ set_composition에 구성품 등록 중...')
  const compositionData: any[] = []

  setCompositions.forEach(set => {
    set.components.forEach(comp => {
      compositionData.push({
        set_barcode: set.setBarcode,
        component_barcode: comp.barcode,
        quantity: comp.quantity,
        created_at: new Date().toISOString()
      })
    })
  })

  const { error: insertCompError } = await supabase
    .from('set_composition')
    .insert(compositionData)

  if (insertCompError) {
    console.error('❌ 구성품 등록 실패:', insertCompError)
    return
  }
  console.log(`✅ ${compositionData.length}개 구성품 등록 완료\n`)

  // 4. 결과 확인
  console.log('4️⃣ 등록 결과 확인:\n')
  for (const set of setCompositions) {
    const { data: comps } = await supabase
      .from('set_composition')
      .select('*')
      .eq('set_barcode', set.setBarcode)

    console.log(`📦 ${set.setBarcode} (${set.setName}):`)
    comps?.forEach(c => {
      console.log(`   - ${c.component_barcode} x ${c.quantity}`)
    })
  }

  console.log('\n✅ 티가든블랭킷 세트 수정 완료!')
}

fixTigardenSets()

