import { NextResponse } from 'next/server'

// 세트 구성 정보
const setCompositions = [
  // Milder 세트
  {
    setBarcode: 'LEC101S00100A',
    setName: '티가든블랭킷_Milder_세트A',
    components: [
      { barcode: 'LEC1012001001', quantity: 2 }, // 라지
      { barcode: 'LEC1012001002', quantity: 1 }  // 미디움
    ]
  },
  {
    setBarcode: 'LEC101S00100B',
    setName: '티가든블랭킷_Milder_세트B',
    components: [
      { barcode: 'LEC1012001001', quantity: 1 }, // 라지
      { barcode: 'LEC1012001002', quantity: 1 }  // 미디움
    ]
  },
  {
    setBarcode: 'LEC101S00100C',
    setName: '티가든블랭킷_Milder_세트C',
    components: [
      { barcode: 'LEC1012001002', quantity: 2 }  // 미디움
    ]
  },
  // Fresher 세트
  {
    setBarcode: 'LEC101S00200A',
    setName: '티가든블랭킷_Fresher_세트A',
    components: [
      { barcode: 'LEC1012002001', quantity: 2 }, // 라지
      { barcode: 'LEC1012002002', quantity: 1 }  // 미디움
    ]
  },
  {
    setBarcode: 'LEC101S00200B',
    setName: '티가든블랭킷_Fresher_세트B',
    components: [
      { barcode: 'LEC1012002001', quantity: 1 }, // 라지
      { barcode: 'LEC1012002002', quantity: 1 }  // 미디움
    ]
  },
  {
    setBarcode: 'LEC101S00200C',
    setName: '티가든블랭킷_Fresher_세트C',
    components: [
      { barcode: 'LEC1012002002', quantity: 2 }  // 미디움
    ]
  },
  // Happier 세트
  {
    setBarcode: 'LEC101S00300A',
    setName: '티가든블랭킷_Happier_세트A',
    components: [
      { barcode: 'LEC1012003001', quantity: 2 }, // 라지
      { barcode: 'LEC1012003002', quantity: 1 }  // 미디움
    ]
  },
  {
    setBarcode: 'LEC101S00300B',
    setName: '티가든블랭킷_Happier_세트B',
    components: [
      { barcode: 'LEC1012003001', quantity: 1 }, // 라지
      { barcode: 'LEC1012003002', quantity: 1 }  // 미디움
    ]
  },
  {
    setBarcode: 'LEC101S00300C',
    setName: '티가든블랭킷_Happier_세트C',
    components: [
      { barcode: 'LEC1012003002', quantity: 2 }  // 미디움
    ]
  }
]

export async function POST() {
  const log: string[] = []

  try {
    log.push('🔧 티가든블랭킷 세트 수정 시작...')

    const setBarcodes = setCompositions.map(s => s.setBarcode)

    // 1. product_barcodes에서 삭제
    log.push('\n1️⃣ product_barcodes에서 세트 바코드 삭제 중...')
    const { error: deleteError } = await supabase
      .from('product_barcodes')
      .delete()
      .in('barcode', setBarcodes)

    if (deleteError) {
      log.push(`❌ 삭제 실패: ${deleteError.message}`)
      return NextResponse.json({ success: false, log: log.join('\n'), error: deleteError.message })
    }
    log.push(`✅ ${setBarcodes.length}개 세트 바코드 삭제 완료`)

    // 2. set_barcodes에 추가
    log.push('\n2️⃣ set_barcodes에 세트 등록 중...')
    const setBarcodesData = setCompositions.map(s => ({
      set_barcode: s.setBarcode,
      set_name: s.setName,
      category: '티가든블랭킷',
      is_active: true,
      created_at: new Date().toISOString(),
      updated_at: new Date().toISOString()
    }))

    const { error: insertSetError } = await supabase
      .from('set_barcodes')
      .insert(setBarcodesData)

    if (insertSetError) {
      log.push(`❌ 세트 등록 실패: ${insertSetError.message}`)
      return NextResponse.json({ success: false, log: log.join('\n'), error: insertSetError.message })
    }
    log.push(`✅ ${setBarcodesData.length}개 세트 등록 완료`)

    // 3. set_composition에 구성품 추가
    log.push('\n3️⃣ set_composition에 구성품 등록 중...')
    const compositionData: any[] = []

    setCompositions.forEach(set => {
      set.components.forEach(comp => {
        compositionData.push({
          set_barcode: set.setBarcode,
          component_barcode: comp.barcode,
          quantity: comp.quantity,
          created_at: new Date().toISOString()
        })
      })
    })

    const { error: insertCompError } = await supabase
      .from('set_composition')
      .insert(compositionData)

    if (insertCompError) {
      log.push(`❌ 구성품 등록 실패: ${insertCompError.message}`)
      return NextResponse.json({ success: false, log: log.join('\n'), error: insertCompError.message })
    }
    log.push(`✅ ${compositionData.length}개 구성품 등록 완료`)

    // 4. 결과 확인
    log.push('\n4️⃣ 등록 결과 확인:')
    const results: any[] = []

    for (const set of setCompositions) {
      const { data: comps } = await supabase
        .from('set_composition')
        .select('*')
        .eq('set_barcode', set.setBarcode)

      log.push(`\n📦 ${set.setBarcode} (${set.setName}):`)
      comps?.forEach(c => {
        log.push(`   - ${c.component_barcode} x ${c.quantity}`)
      })

      results.push({
        setBarcode: set.setBarcode,
        setName: set.setName,
        components: comps
      })
    }

    log.push('\n✅ 티가든블랭킷 세트 수정 완료!')

    return NextResponse.json({
      success: true,
      log: log.join('\n'),
      results
    })

  } catch (error) {
    log.push(`\n❌ 오류 발생: ${error instanceof Error ? error.message : String(error)}`)
    return NextResponse.json({
      success: false,
      log: log.join('\n'),
      error: error instanceof Error ? error.message : String(error)
    }, { status: 500 })
  }
}

